// Extract topic + resource id from Meli notification body.
// Meli sends: { resource: '/orders/2000003508419013', topic: 'orders_v2', user_id, ... }
const webhook = $('Meli Orders').item.json;
const body = webhook.body || webhook;
const topic = body.topic;
const resource = body.resource || '';
const resourceId = resource.split('/').filter(Boolean).pop();

if (!resourceId) {
  throw new Error('Missing resource id in Meli notification');
}

return { json: { meli_order_id: resourceId, topic, sent_at: body.sent } };

// Merge order + shipment + billing_info into the canonical Sabana payload.
// Sources (read by node name so reordering does not break the flow):
//   - Get Meli Order            : order header, buyer (basic), order_items, payments
//   - Get Meli Shipment         : receiver_address (preferred for shipping), receiver_phone, shipping cost, ETA
//   - Get Meli Billing Info     : identification (type+number) → TaxGroup+TaxID, fiscal name split, fiscal address fallback
const order = $('Get Meli Order').first().json;
const shipment = (() => { try { return $('Get Shipment Info').first().json || {}; } catch (e) { return {}; } })();
const billing = (() => {
  try { return ($('get_billing_info').first().json || {}).buyer?.billing_info || {}; }
  catch (e) { return {}; }
})();

// --- Address: prefer shipment, fall back to billing_info.address ---
const recv  = shipment.receiver_address || {};
const bAddr = billing.address || {};
const useShip = !!(recv.street_name || recv.address_line);

const street  = useShip
    ? [recv.street_name, recv.street_number].filter(Boolean).join(' ').trim()
    : [bAddr.street_name, bAddr.street_number].filter(Boolean).join(' ').trim();
const city    = useShip ? (recv.city?.name || '') : (bAddr.city_name || '');
const region  = useShip ? (recv.state?.name || '') : (bAddr.state?.name || '');
const country = useShip ? (recv.country?.id || '') : (bAddr.country_id || '');
const postal  = useShip ? (recv.zip_code || '') : (bAddr.zip_code || '');
const comment = useShip ? (recv.comment || '') : '';
const locName = useShip ? (recv.receiver_name || street) : street;
const phone   = useShip ? (recv.receiver_phone || '') : '';

// --- Identification → tax group + tax id ---
const ident    = billing.identification || {};
const taxId    = ident.number || '';
const taxGroup = ident.type   || '';   // 'CI' | 'RUT' | 'DNI' | …

// --- Name: billing_info wins (fiscal); fallback to order.buyer ---
const firstName = billing.name      || order.buyer?.first_name || '';
const lastName  = billing.last_name || order.buyer?.last_name  || '';

// --- Freight: shipment.shipping_option.cost → payments[0].shipping_cost → 0 ---
const freight = shipment?.shipping_option?.cost
              ?? order.payments?.[0]?.shipping_cost
              ?? 0;

// --- ETA ---
const datePromised = shipment?.shipping_option?.estimated_delivery_time?.date?.substring(0,10) || null;

// --- Currency / dates ---
const currencyIso = order.currency_id || 'USD';
const dateOrdered = (order.date_created || new Date().toISOString()).substring(0,10);

const payload = {
  store: { StoreCode: 'Mercado Libre' },
  order: {
    DocTypeName: null,
    CurrencyISOCode: currencyIso,
    PaymentRule: 'P',
    DateOrdered: dateOrdered,
    DatePromised: datePromised,
    DocumentNo: order.id,
    Description: `Pedido MercadoLibre #${order.id} - Canal: ${order.context?.site || ''}`.trim(),
    FreightAmt: freight,
    FreightCostRule: 'I'
  },
  bpartner: {
    BPartnerValue: 'MELI-' + (order.buyer?.id || ''),
    Name:  firstName,
    Name2: lastName,
    TaxID: taxId,
    TaxGroupName: taxGroup,
    IsCustomer: 'Y',
    IsVendor: 'N'
  },
  bpartner_location: {
    LocationName: locName || ('Meli buyer ' + (order.buyer?.id || '')),
    Address1: street || (useShip ? (recv.address_line || '') : ''),
    Address2: comment,
    City: city,
    RegionName: region,
    CountryCode: country,
    PostalCode: postal,
    Phone: phone,
    IsShipTo: 'Y',
    IsBillTo: 'Y'
  },
  order_lines: (order.order_items || []).map((it, idx) => {
    const item = it.item || {};
    return {
      Line: (idx + 1) * 10,
      ProductPublicationCode: item.id,
      PublishCode: item.id,
      ProductValue: item.seller_sku,
      ProductName: item.title,
      QtyOrdered: it.quantity,
      PriceActual: it.unit_price,
      PriceList: (it.gross_price != null ? it.gross_price : it.unit_price),
      Discount: 0,
      Description: [item.title, item.condition ? `Condición: ${item.condition}` : '']
                     .filter(Boolean).join(' — ')
    };
  })
};

return [{ json: payload }];

// Obtenemos el primer ítem del flujo
const item = $('Get Shipment Label').first();

// Extraemos los metadatos de la propiedad binaria llamada 'data'
const fileMetadata = item.binary.data;
const sizeString = fileMetadata.fileSize; // Esto es "71.3 kB" o "2.5 MB", etc.
const rawName = fileMetadata.fileName; 
const match = rawName.match(/shipment_ids=(\d+)/);
const cleanName = match ? `${match[1]}.pdf` : rawName;

// Extraemos el número (ej: 71.3)
const number = parseFloat(sizeString);

// Detectamos la unidad (B, kB, MB)
let sizeInBytes = number;
if (sizeString.includes('kB')) {
  sizeInBytes = Math.round(number * 1024);
} else if (sizeString.includes('MB')) {
  sizeInBytes = Math.round(number * 1024 * 1024);
} else if (sizeString.includes('GB')) {
  sizeInBytes = Math.round(number * 1024 * 1024 * 1024);
}

// --- EL CAMBIO CLAVE PARA EL NUEVO MOTOR BINARIO DE n8n ---
// Clonamos la estructura binaria original para mantener la referencia física del archivo
const newBinaryData = { ...item.binary };

// Modificamos el fileName dentro de los metadatos internos del binario
if (newBinaryData.data) {
  newBinaryData.data = {
    ...newBinaryData.data,
    fileName: cleanName
  };
}

return {
  json: {
    fileName: cleanName,
    fileExtension: fileMetadata.fileExtension,
    mimeType: fileMetadata.mimeType,
    fileSize: sizeInBytes
  },
  // Retornamos el binario clonado y actualizado con el nombre correcto
  binary: newBinaryData
};

// 1. Obtenemos el primer ítem específicamente del nodo "Get Meli Shipment"
const item = $items("Get Shipment Label")[0];

if (!item || !item.binary || !item.binary.data) {
  throw new Error("No se encontró el archivo binario 'data' en el nodo Get Meli Shipment");
}

const fileMetadata = item.binary.data;
const rawName = fileMetadata.fileName; 

// 2. Limpiamos el nombre usando tu expresión regular (RegEx)
const match = rawName.match(/shipment_ids=(\d+)/);
const cleanName = match ? `${match[1]}.pdf` : rawName;

// 3. LA SOLUCIÓN DEFINITIVA PARA EL NUEVO MOTOR BINARIO:
// Usamos el helper oficial para clonar físicamente el archivo evitando errores circulares
const newBinaryData = { ...item.binary };

// Modificamos el fileName dentro de los metadatos internos del binario
if (newBinaryData.data) {
  newBinaryData.data = {
    ...newBinaryData.data,
    fileName: cleanName
  };
}
// Retornamos únicamente la estructura JSON básica que requiere n8n y el binario modificado
return {
  json: {
    message: "Archivo procesado correctamente"
  },
  binary: newBinaryData
};

