// Enriquece atributos string con sugerencias (p. ej. BRAND, COLOR) con la lista COMPLETA
// de valores desde el endpoint top_values del catalog_domain de MELI (incluye marcas que
// no entran en el top de la categoría, p. ej. Kassel). Si algo falla, deja los valores de
// la categoría como estaban. value_type se mantiene tal cual (no cambia el tipo en SP034).
const token = $('Get Token for Attributes').first().json.access_token;
const categoryId = $('Webhook Get Attributes').first().json.query.category_id;

// 1) Dominio de catálogo de la categoría (para armar la URL de top_values)
let domain = null;
try {
  const category = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.mercadolibre.com/categories/${categoryId}`,
    headers: { Authorization: `Bearer ${token}` },
    json: true
  });
  domain = (category && category.settings && category.settings.catalog_domain) || null;
} catch (e) {}

const items = $input.all().map(v => v.json);
const result = [];

for (const attribute of items) {
  let values = Array.isArray(attribute.values) ? attribute.values : [];

  // Solo string con sugerencias: traer la lista completa (top_values).
  const isStringWithValues = attribute.value_type === 'string' && values.length > 0;
  if (domain && isStringWithValues) {
    try {
      const topValues = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://api.mercadolibre.com/catalog_domains/${domain}/attributes/${attribute.id}/top_values`,
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: { known_attributes: [] },
        json: true
      });
      if (Array.isArray(topValues) && topValues.length > 0) {
        values = topValues;
      }
    } catch (e) {}
  }

  result.push({
    code: attribute.id,
    name: attribute.name,
    description: attribute.hint,
    mandatory: !!(attribute.tags && (attribute.tags.required || attribute.tags.catalog_required)),
    max_length: attribute.value_max_length,
    value_type: attribute.value_type,
    default_unit: attribute.default_unit,
    allowed_units: attribute.allowed_units,
    values: values.map(v => ({ code: v.id, name: v.name }))
  });
}

return result;

// Extract media files from webhook
const items = [];
const webhookData = $('Webhook (PublishCallbacks)').first().json.body;

// Check if media exists
if (!webhookData || !webhookData.media) {
  // No media files, return empty array
  console.log('No media files found in webhook data');
  return [];
}

const mediaFiles = webhookData.media;
const productCode = webhookData.document.code;
const clientUuid = webhookData.document.client;
const cacheKey = `ml-images:${clientUuid}-${productCode}`;

console.log(`========================================`);
console.log(`Processing ${mediaFiles.length} media files for product ${productCode}`);
console.log(`Full media array:`, JSON.stringify(mediaFiles, null, 2));

// Create an item for each media file
for (let i = 0; i < mediaFiles.length; i++) {
  const filePath = mediaFiles[i];
  const filename = filePath.split('/').pop();
  const s3Key = filePath.startsWith('/') ? filePath.substring(1) : filePath;

  console.log(`Item ${i}: filename=${filename}, path=${filePath}`);

  items.push({
    json: {
      filename: filename,
      s3_key: s3Key,
      s3_path: filePath,
      product_code: productCode,
      client_uuid: clientUuid,
      cache_key: cacheKey,
      index: i
    }
  });
}

console.log(`Created ${items.length} items for processing`);
return items;

