// Error Handler - Formats error response for backend
const webhookData = $('Webhook (PublishCallbacks)').first().json.body;

// In n8n continueErrorOutput, error is merged into item.json alongside the original data.
// $input.first().json.error contains the AxiosError (message, status, etc.)
// $input.item.error contains n8n-level error metadata (may be undefined in some versions)
const jsonError = $input.first().json?.error || null;
const itemError = $input.item?.error || null;
const error = (itemError && Object.keys(itemError).length > 0) ? itemError : (jsonError || {});

let errorMessage = 'Unknown error occurred';
let httpResponseBody = null;

// Strategy 1: n8n item-level error has context.responseBody (direct ML response)
if (itemError && itemError.context && itemError.context.responseBody) {
  try {
    httpResponseBody = JSON.parse(itemError.context.responseBody);
  } catch(e) {
    httpResponseBody = { raw: itemError.context.responseBody };
  }
}

// Strategy 2: Parse the HTTP error message string "400 - \"{...}\"" from jsonError
if (!httpResponseBody && jsonError && jsonError.message) {
  const match = jsonError.message.match(/^\d+ - "(.+)"$/s);
  if (match) {
    try {
      httpResponseBody = JSON.parse(match[1].replace(/\\"/g, '"'));
    } catch(e) {
      httpResponseBody = { raw: match[1] };
    }
  } else {
    errorMessage = jsonError.message;
  }
}

// Extract human-readable message from ML response
if (httpResponseBody) {
  if (httpResponseBody.cause && httpResponseBody.cause.length > 0) {
    const errors = httpResponseBody.cause.filter(c => c.type === 'error');
    if (errors.length > 0) {
      errorMessage = 'MercadoLibre: ' + errors.map(c => c.message || c.code).join('; ');
    } else if (httpResponseBody.message) {
      errorMessage = 'MercadoLibre: ' + httpResponseBody.message;
    }
  } else if (httpResponseBody.message) {
    errorMessage = 'MercadoLibre: ' + httpResponseBody.message;
  } else if (httpResponseBody.error) {
    errorMessage = 'MercadoLibre: ' + httpResponseBody.error;
  }
} else if (error.message) {
  errorMessage = error.message;
}

return [{
  json: {
    success: false,
    error: `Error in workflow: ${errorMessage}`,
    error_details: {
      message: errorMessage,
      product_code: webhookData?.document?.code || 'unknown',
      timestamp: new Date().toISOString(),
      ml_response: httpResponseBody,
      http_status: jsonError?.status || null
    }
  }
}];

